		let yz;
		let zx;
		let xs;
		let ys;
		let zs;
		xy = x * y;
		yz = y * z;
		zx = z * x;
		xs = x * s;
		ys = y * s;
		zs = z * s;
		m = m || math.mat4();
		m[0] = q * x * x + c;
		m[1] = q * xy + zs;
		m[2] = q * zx - ys;
		m[3] = 0;
		m[4] = q * xy - zs;
		m[5] = q * y * y + c;
		m[6] = q * yz + xs;
		m[7] = 0;
		m[8] = q * zx + ys;
		m[9] = q * yz - xs;
		m[10] = q * z * z + c;
		m[11] = 0;
		m[12] = 0;
		m[13] = 0;
		m[14] = 0;
		m[15] = 1;
		return m;
