/**
* @desc Creates a box-shaped lines {@link Geometry}.
*
* ## Usage
*
* In the example below we'll create a {@link Mesh} with a box-shaped {@link ReadableGeometry} that has lines primitives.
*
* [[Run this example](/examples/index.html#geometry_builders_buildBoxLinesGeometry)]
*
* ````javascript
* import {Viewer, Mesh, buildBoxLinesGeometry, ReadableGeometry, PhongMaterial} from "xeokit-sdk.es.js";
*
* const viewer = new Viewer({
*         canvasId: "myCanvas"
* });
*
* viewer.scene.camera.eye = [0, 0, 5];
* viewer.scene.camera.look = [0, 0, 0];
* viewer.scene.camera.up = [0, 1, 0];
*
* new Mesh(viewer.scene, {
*      geometry: new ReadableGeometry(viewer.scene, buildBoxLinesGeometry({
*         center: [0,0,0],
*         xSize: 1,  // Half-size on each axis
*         ySize: 1,
*         zSize: 1
*      })),
*      material: new PhongMaterial(viewer.scene, {
*         emissive: [0,1,0]
*      })
* });
* ````
*
* @function buildBoxLinesGeometry
* @param {*} [cfg] Configs
* @param {String} [cfg.id] Optional ID, unique among all components in the parent {@link Scene}, generated automatically when omitted.
* @param {Number[]} [cfg.center]  3D point indicating the center position.
* @param {Number} [cfg.xSize=1.0]  Half-size on the X-axis.
* @param {Number} [cfg.ySize=1.0]  Half-size on the Y-axis.
* @param {Number} [cfg.zSize=1.0]  Half-size on the Z-axis.
* @returns {Object} Configuration for a {@link Geometry} subtype.
*/
function buildBoxLinesGeometry(cfg = {}) {
	let xSize = cfg.xSize || 1;
	if (xSize < 0) {
		console.error("negative xSize not allowed - will invert");
		xSize *= -1;
	}
	let ySize = cfg.ySize || 1;
	if (ySize < 0) {
		console.error("negative ySize not allowed - will invert");
		ySize *= -1;
	}
	let zSize = cfg.zSize || 1;
	if (zSize < 0) {
		console.error("negative zSize not allowed - will invert");
		zSize *= -1;
	}
	const center = cfg.center;
	const centerX = center ? center[0] : 0;
	const centerY = center ? center[1] : 0;
	const centerZ = center ? center[2] : 0;
	const xmin = -xSize + centerX;
	const ymin = -ySize + centerY;
	const zmin = -zSize + centerZ;
	const xmax = xSize + centerX;
	const ymax = ySize + centerY;
	const zmax = zSize + centerZ;
	return utils.apply(cfg, {
		primitive: "lines",
		positions: [
			xmin,
			ymin,
			zmin,
			xmin,
			ymin,
			zmax,
			xmin,
			ymax,
			zmin,
			xmin,
			ymax,
			zmax,
			xmax,
			ymin,
			zmin,
			xmax,
			ymin,
			zmax,
			xmax,
			ymax,
			zmin,
			xmax,
			ymax,
			zmax
		],
		indices: [
			0,
			1,
			1,
			3,
			3,
			2,
			2,
			0,
			4,
			5,
			5,
			7,
			7,
			6,
			6,
			4,
			0,
			4,
			1,
			5,
			2,
			6,
			3,
			7
		]
	});
}
/**
* @desc Creates a box-shaped lines {@link Geometry} from AABB.
*
* ## Usage
*
* In the example below we'll create a {@link Mesh} with a box-shaped {@link ReadableGeometry} that has lines primitives.
* This box will be created from AABB of a model.
*
* [[Run this example](/examples/index.html#geometry_builders_buildBoxLinesGeometryFromAABB)]
*
* ````javascript
*     import {Viewer, Mesh, Node, buildBoxGeometry, buildBoxLinesGeometryFromAABB, ReadableGeometry, PhongMaterial} from "../../dist/xeokit-sdk.min.es.js";
*
*     const viewer = new Viewer({
*         canvasId: "myCanvas"
*     });
*
*     viewer.scene.camera.eye = [-21.80, 4.01, 6.56];
*     viewer.scene.camera.look = [0, -5.75, 0];
*     viewer.scene.camera.up = [0.37, 0.91, -0.11];
*
*     const boxGeometry = new ReadableGeometry(viewer.scene, buildBoxGeometry({
*         xSize: 1,
*         ySize: 1,
*         zSize: 1
*     }));
*
*     new Node(viewer.scene, {
*         id: "table",
*         isModel: true, // <--------------------- Node represents a model
*         rotation: [0, 50, 0],
*         position: [0, 0, 0],
*         scale: [1, 1, 1],
*
*         children: [
*
*             new Mesh(viewer.scene, { // Red table leg
*                 id: "redLeg",
*                 isObject: true, // <---------- Node represents an object
*                 position: [-4, -6, -4],
*                 scale: [1, 3, 1],
*                 rotation: [0, 0, 0],
*                 geometry: boxGeometry,
*                 material: new PhongMaterial(viewer.scene, {
*                     diffuse: [1, 0.3, 0.3]
*                 })
*             }),
*
*             new Mesh(viewer.scene, { // Green table leg
*                 id: "greenLeg",
*                 isObject: true, // <---------- Node represents an object
*                 position: [4, -6, -4],
*                 scale: [1, 3, 1],
*                 rotation: [0, 0, 0],
*                 geometry: boxGeometry,
*                 material: new PhongMaterial(viewer.scene, {
*                     diffuse: [0.3, 1.0, 0.3]
*                 })
*             }),
*
*             new Mesh(viewer.scene, {// Blue table leg
*                 id: "blueLeg",
*                 isObject: true, // <---------- Node represents an object
*                 position: [4, -6, 4],
*                 scale: [1, 3, 1],
*                 rotation: [0, 0, 0],
*                 geometry: boxGeometry,
*                 material: new PhongMaterial(viewer.scene, {
*                     diffuse: [0.3, 0.3, 1.0]
*                 })
*             }),
*
*             new Mesh(viewer.scene, {  // Yellow table leg
*                 id: "yellowLeg",
*                 isObject: true, // <---------- Node represents an object
*                 position: [-4, -6, 4],
*                 scale: [1, 3, 1],
*                 rotation: [0, 0, 0],
*                 geometry: boxGeometry,
*                 material: new PhongMaterial(viewer.scene, {
*                     diffuse: [1.0, 1.0, 0.0]
*                 })
*             }),
*
*             new Mesh(viewer.scene, { // Purple table top
*                 id: "tableTop",
*                 isObject: true, // <---------- Node represents an object
*                 position: [0, -3, 0],
*                 scale: [6, 0.5, 6],
*                 rotation: [0, 0, 0],
*                 geometry: boxGeometry,
*                 material: new PhongMaterial(viewer.scene, {
*                     diffuse: [1.0, 0.3, 1.0]
*                 })
*             })
*         ]
*     });
*
*     let aabb = viewer.scene.aabb;
*     console.log(aabb);
*
*     new Mesh(viewer.scene, {
*         geometry: new ReadableGeometry(viewer.scene, buildBoxLinesGeometryFromAABB({
*             id: "aabb",
*             aabb: aabb,
*         })),
*         material: new PhongMaterial(viewer.scene, {
*             emissive: [0, 1,]
*         })
*     });
* ````
*
* @function buildBoxLinesGeometryFromAABB
* @param {*} [cfg] Configs
* @param {String} [cfg.id] Optional ID, unique among all components in the parent {@link Scene}, generated automatically when omitted.
* @param {Number[]} [cfg.aabb]  AABB for which box will be created.
* @returns {Object} Configuration for a {@link Geometry} subtype.
*/
function buildBoxLinesGeometryFromAABB(cfg = {}) {
	return buildBoxLinesGeometry({
		id: cfg.id,
		center: [
			(cfg.aabb[0] + cfg.aabb[3]) / 2,
			(cfg.aabb[1] + cfg.aabb[4]) / 2,
			(cfg.aabb[2] + cfg.aabb[5]) / 2
		],
		xSize: Math.abs(cfg.aabb[3] - cfg.aabb[0]) / 2,
		ySize: Math.abs(cfg.aabb[4] - cfg.aabb[1]) / 2,
		zSize: Math.abs(cfg.aabb[5] - cfg.aabb[2]) / 2
	});
}
/**
* @desc Creates a cylinder-shaped {@link Geometry}.
*
* ## Usage
*
* Creating a {@link Mesh} with a cylinder-shaped {@link ReadableGeometry} :
*
* [[Run this example](/examples/index.html#geometry_builders_buildCylinderGeometry)]
*
* ````javascript
*
* import {Viewer, Mesh, buildCylinderGeometry, ReadableGeometry, PhongMaterial, Texture} from "xeokit-sdk.es.js";
*
* const viewer = new Viewer({
*      canvasId: "myCanvas"
*  });
*
* viewer.camera.eye = [0, 0, 5];
* viewer.camera.look = [0, 0, 0];
* viewer.camera.up = [0, 1, 0];
*
* new Mesh(viewer.scene, {
*      geometry: new ReadableGeometry(viewer.scene, buildCylinderGeometry({
*          center: [0,0,0],
*          radiusTop: 2.0,
*          radiusBottom: 2.0,
*          height: 5.0,
*          radialSegments: 20,
*          heightSegments: 1,
*          openEnded: false
*      }),
*      material: new PhongMaterial(viewer.scene, {
*         diffuseMap: new Texture(viewer.scene, {
*             src: "textures/diffuse/uvGrid2.jpg"
*         })
*      })
* });
* ````
*
* @function buildCylinderGeometry
* @param {*} [cfg] Configs
* @param {String} [cfg.id] Optional ID for the {@link Geometry}, unique among all components in the parent {@link Scene}, generated automatically when omitted.
* @param {Number[]} [cfg.center]  3D point indicating the center position.
* @param {Number} [cfg.radiusTop=1]  Radius of top.
* @param {Number} [cfg.radiusBottom=1]  Radius of bottom.
* @param {Number} [cfg.height=1] Height.
* @param {Number} [cfg.radialSegments=60]  Number of horizontal segments.
* @param {Number} [cfg.heightSegments=1]  Number of vertical segments.
* @param {Boolean} [cfg.openEnded=false]  Whether or not the cylinder has solid caps on the ends.
* @returns {Object} Configuration for a {@link Geometry} subtype.
*/
function buildCylinderGeometry(cfg = {}) {
	let radiusTop = cfg.radiusTop || 1;
	if (radiusTop < 0) {
		console.error("negative radiusTop not allowed - will invert");
		radiusTop *= -1;
	}
	let radiusBottom = cfg.radiusBottom || 1;
	if (radiusBottom < 0) {
		console.error("negative radiusBottom not allowed - will invert");
		radiusBottom *= -1;
	}
	let height = cfg.height || 1;
	if (height < 0) {
		console.error("negative height not allowed - will invert");
		height *= -1;
	}
	let radialSegments = cfg.radialSegments || 32;
	if (radialSegments < 0) {
		console.error("negative radialSegments not allowed - will invert");
		radialSegments *= -1;
	}
	if (radialSegments < 3) radialSegments = 3;
	let heightSegments = cfg.heightSegments || 1;
	if (heightSegments < 0) {
		console.error("negative heightSegments not allowed - will invert");
		heightSegments *= -1;
	}
	if (heightSegments < 1) heightSegments = 1;
	const openEnded = !!cfg.openEnded;
	let center = cfg.center;
	const centerX = center ? center[0] : 0;
	const centerY = center ? center[1] : 0;
	const centerZ = center ? center[2] : 0;
	const heightHalf = height / 2;
	const heightLength = height / heightSegments;
	const radialAngle = 2 * Math.PI / radialSegments;
	const radialLength = 1 / radialSegments;
	const radiusChange = (radiusTop - radiusBottom) / heightSegments;
	const positions = [];
	const normals = [];
	const uvs = [];
	const indices = [];
	let h;
	let i;
	let x;
	let z;
	let currentRadius;
	let currentHeight;
	let first;
	let second;
	let startIndex;
	let tu;
	let tv;
	const normalY = (90 - Math.atan(height / (radiusBottom - radiusTop)) * 180 / Math.PI) / 90;
	for (h = 0; h <= heightSegments; h++) {
		currentRadius = radiusTop - h * radiusChange;
		currentHeight = heightHalf - h * heightLength;
		for (i = 0; i <= radialSegments; i++) {
			x = Math.sin(i * radialAngle);
			z = Math.cos(i * radialAngle);
			normals.push(currentRadius * x);
			normals.push(normalY);
			normals.push(currentRadius * z);
			uvs.push(i * radialLength);
			uvs.push(h * 1 / heightSegments);
			positions.push(currentRadius * x + centerX);
			positions.push(currentHeight + centerY);
			positions.push(currentRadius * z + centerZ);
		}
	}
	for (h = 0; h < heightSegments; h++) for (i = 0; i <= radialSegments; i++) {
		first = h * (radialSegments + 1) + i;
		second = first + radialSegments;
		indices.push(first);
		indices.push(second);
		indices.push(second + 1);
		indices.push(first);
		indices.push(second + 1);
		indices.push(first + 1);
	}
	if (!openEnded && radiusTop > 0) {
		startIndex = positions.length / 3;
		normals.push(0);
		normals.push(1);
		normals.push(0);
		uvs.push(.5);
		uvs.push(.5);
		positions.push(0 + centerX);
		positions.push(heightHalf + centerY);
		positions.push(0 + centerZ);
		for (i = 0; i <= radialSegments; i++) {
			x = Math.sin(i * radialAngle);
			z = Math.cos(i * radialAngle);
			tu = .5 * Math.sin(i * radialAngle) + .5;
			tv = .5 * Math.cos(i * radialAngle) + .5;
			normals.push(radiusTop * x);
			normals.push(1);
			normals.push(radiusTop * z);
			uvs.push(tu);
			uvs.push(tv);
			positions.push(radiusTop * x + centerX);
			positions.push(heightHalf + centerY);
			positions.push(radiusTop * z + centerZ);
		}
		for (i = 0; i < radialSegments; i++) {
			center = startIndex;
			first = startIndex + 1 + i;
			indices.push(first);
			indices.push(first + 1);
			indices.push(center);
		}
	}
	if (!openEnded && radiusBottom > 0) {
		startIndex = positions.length / 3;
		normals.push(0);
		normals.push(-1);
		normals.push(0);
		uvs.push(.5);
		uvs.push(.5);
		positions.push(0 + centerX);
		positions.push(0 - heightHalf + centerY);
		positions.push(0 + centerZ);
		for (i = 0; i <= radialSegments; i++) {
			x = Math.sin(i * radialAngle);
			z = Math.cos(i * radialAngle);
			tu = .5 * Math.sin(i * radialAngle) + .5;
			tv = .5 * Math.cos(i * radialAngle) + .5;
			normals.push(radiusBottom * x);
			normals.push(-1);
			normals.push(radiusBottom * z);
			uvs.push(tu);
			uvs.push(tv);
			positions.push(radiusBottom * x + centerX);
			positions.push(0 - heightHalf + centerY);
			positions.push(radiusBottom * z + centerZ);
		}
		for (i = 0; i < radialSegments; i++) {
			center = startIndex;
			first = startIndex + 1 + i;
			indices.push(center);
			indices.push(first + 1);
			indices.push(first);
		}
	}
	return utils.apply(cfg, {
		positions,
		normals,
		uv: uvs,
		indices
	});
}
/**
* @desc Creates a grid-shaped {@link Geometry}.
*
* ## Usage
*
* Creating a {@link Mesh} with a GridGeometry and a {@link PhongMaterial}:
*
* [[Run this example](/examples/index.html#geometry_builders_buildGridGeometry)]
*
* ````javascript
* import {Viewer, Mesh, buildGridGeometry, VBOGeometry, PhongMaterial, Texture} from "xeokit-sdk.es.js";
*
* const viewer = new Viewer({
*      canvasId: "myCanvas"
* });
*
* viewer.camera.eye = [0, 0, 5];
* viewer.camera.look = [0, 0, 0];
* viewer.camera.up = [0, 1, 0];
*
* new Mesh(viewer.scene, {
*      geometry: new VBOGeometry(viewer.scene, buildGridGeometry({
*          size: 1000,
*          divisions: 500
*      })),
*      material: new PhongMaterial(viewer.scene, {
*          color: [0.0, 0.0, 0.0],
*          emissive: [0.4, 0.4, 0.4]
*      }),
*      position: [0, -1.6, 0]
* });
* ````
*
* @function buildGridGeometry
* @param {*} [cfg] Configs
* @param {String} [cfg.id] Optional ID for the {@link Geometry}, unique among all components in the parent {@link Scene}, generated automatically when omitted.
* @param {Number} [cfg.size=1] Dimension on the X and Z-axis.
* @param {Number} [cfg.divisions=1] Number of divisions on X and Z axis..
* @returns {Object} Configuration for a {@link Geometry} subtype.
*/
function buildGridGeometry(cfg = {}) {
	let size = cfg.size || 1;
	if (size < 0) {
		console.error("negative size not allowed - will invert");
		size *= -1;
	}
	let divisions = cfg.divisions || 1;
	if (divisions < 0) {
		console.error("negative divisions not allowed - will invert");
		divisions *= -1;
	}
	if (divisions < 1) divisions = 1;
	size = size || 10;
	divisions = divisions || 10;
	const step = size / divisions;
	const halfSize = size / 2;
	const positions = [];
	const indices = [];
	let l = 0;
	for (let i = 0, k = -halfSize; i <= divisions; i++, k += step) {
		positions.push(-halfSize);
		positions.push(0);
		positions.push(k);
		positions.push(halfSize);
		positions.push(0);
		positions.push(k);
		positions.push(k);
		positions.push(0);
		positions.push(-halfSize);
		positions.push(k);
		positions.push(0);
		positions.push(halfSize);
		indices.push(l++);
		indices.push(l++);
		indices.push(l++);
		indices.push(l++);
	}
	return utils.apply(cfg, {
		primitive: "lines",
		positions,
		indices
	});
}
/**
* @desc Creates a plane-shaped {@link Geometry}.
*
* ## Usage
*
* Creating a {@link Mesh} with a PlaneGeometry and a {@link PhongMaterial} with diffuse {@link Texture}:
*
* [[Run this example](https://xeokit.github.io/xeokit-sdk/examples/scenegraph/#buildPlaneGeometry)]
*
* ````javascript
* import {Viewer, Mesh, buildPlaneGeometry, ReadableGeometry, PhongMaterial, Texture} from "xeokit-sdk.es.js";
*
* const viewer = new Viewer({
*      canvasId: "myCanvas"
* });
*
* viewer.camera.eye = [0, 0, 5];
* viewer.camera.look = [0, 0, 0];
* viewer.camera.up = [0, 1, 0];

* new Mesh(viewer.scene, {
*      geometry: new ReadableGeometry(viewer.scene, buildPlaneGeometry({
*          center: [0,0,0],
*          xSize: 2,
*          zSize: 2,
*          xSegments: 10,
*          zSegments: 10
*      }),
*      material: new PhongMaterial(viewer.scene, {
*          diffuseMap: new Texture(viewer.scene, {
*              src: "textures/diffuse/uvGrid2.jpg"
*          })
*      })
*  });
* ````
*
* @function buildPlaneGeometry
* @param {*} [cfg] Configs
* @param {Number[]} [cfg.center]  3D point indicating the center position.
* @param {String} [cfg.id] Optional ID for the {@link Geometry}, unique among all components in the parent {@link Scene}, generated automatically when omitted.
* @param {Number} [cfg.xSize=1] Dimension on the X-axis.
* @param {Number} [cfg.zSize=1] Dimension on the Z-axis.
* @param {Number} [cfg.xSegments=1] Number of segments on the X-axis.
* @param {Number} [cfg.zSegments=1] Number of segments on the Z-axis.
* @returns {Object} Configuration for a {@link Geometry} subtype.
*/
function buildPlaneGeometry(cfg = {}) {
	let xSize = cfg.xSize || 1;
	if (xSize < 0) {
		console.error("negative xSize not allowed - will invert");
		xSize *= -1;
	}
	let zSize = cfg.zSize || 1;
	if (zSize < 0) {
		console.error("negative zSize not allowed - will invert");
		zSize *= -1;
	}
	let xSegments = cfg.xSegments || 1;
	if (xSegments < 0) {
		console.error("negative xSegments not allowed - will invert");
		xSegments *= -1;
	}
	if (xSegments < 1) xSegments = 1;
	let zSegments = cfg.xSegments || 1;
	if (zSegments < 0) {
		console.error("negative zSegments not allowed - will invert");
		zSegments *= -1;
	}
	if (zSegments < 1) zSegments = 1;
	const center = cfg.center;
	const centerX = center ? center[0] : 0;
	const centerY = center ? center[1] : 0;
	const centerZ = center ? center[2] : 0;
	const halfWidth = xSize / 2;
	const halfHeight = zSize / 2;
	const planeX = Math.floor(xSegments) || 1;
	const planeZ = Math.floor(zSegments) || 1;
	const planeX1 = planeX + 1;
	const planeZ1 = planeZ + 1;
	const segmentWidth = xSize / planeX;
	const segmentHeight = zSize / planeZ;
	const positions = new Float32Array(planeX1 * planeZ1 * 3);
	const normals = new Float32Array(planeX1 * planeZ1 * 3);
	const uvs = new Float32Array(planeX1 * planeZ1 * 2);
	let offset = 0;
	let offset2 = 0;
	let iz;
	let ix;
	let x;
	let a;
	let b;
	let c;
	let d;
	for (iz = 0; iz < planeZ1; iz++) {
		const z = iz * segmentHeight - halfHeight;
		for (ix = 0; ix < planeX1; ix++) {
			x = ix * segmentWidth - halfWidth;
			positions[offset] = x + centerX;
			positions[offset + 1] = centerY;
			positions[offset + 2] = -z + centerZ;
			normals[offset + 1] = 1;
			uvs[offset2] = ix / planeX;
			uvs[offset2 + 1] = (planeZ - iz) / planeZ;
			offset += 3;
			offset2 += 2;
		}
	}
	offset = 0;
	const indices = new (positions.length / 3 > 65535 ? Uint32Array : Uint16Array)(planeX * planeZ * 6);
	for (iz = 0; iz < planeZ; iz++) for (ix = 0; ix < planeX; ix++) {
		a = ix + planeX1 * iz;
		b = ix + planeX1 * (iz + 1);
		c = ix + 1 + planeX1 * (iz + 1);
		d = ix + 1 + planeX1 * iz;
		indices[offset] = d;
		indices[offset + 1] = b;
		indices[offset + 2] = a;
		indices[offset + 3] = d;
		indices[offset + 4] = c;
		indices[offset + 5] = b;
		offset += 6;
	}
	return utils.apply(cfg, {
		positions,
		normals,
		uv: uvs,
		indices
	});
}
/**
* @desc Creates a sphere-shaped {@link Geometry}.
*
* ## Usage
*
* Creating a {@link Mesh} with a sphere-shaped {@link ReadableGeometry} :
*
* [[Run this example](https://xeokit.github.io/xeokit-sdk/examples/scenegraph/#buildSphereGeometry)]
*
* ````javascript
* import {Viewer, Mesh, buildSphereGeometry, ReadableGeometry, PhongMaterial, Texture} from "xeokit-sdk.es.js";
*
* const viewer = new Viewer({
*     canvasId: "myCanvas"
* });
*
* viewer.camera.eye = [0, 0, 5];
* viewer.camera.look = [0, 0, 0];
* viewer.camera.up = [0, 1, 0];
*
* new Mesh(viewer.scene, {
*      geometry: new ReadableGeometry(viewer.scene, buildSphereGeometry({
*          center: [0,0,0],
*          radius: 1.5,
*          heightSegments: 60,
*          widthSegments: 60
*      }),
*      material: new PhongMaterial(viewer.scene, {
*         diffuseMap: new Texture(viewer.scene, {
*             src: "textures/diffuse/uvGrid2.jpg"
*         })
*      })
* });
* ````
*
* @function buildSphereGeometry
* @param {*} [cfg] Configs
* @param {String} [cfg.id] Optional ID for the {@link Geometry}, unique among all components in the parent {@link Scene}, generated automatically when omitted.
* @param {Number[]} [cfg.center]  3D point indicating the center position.
* @param {Number} [cfg.radius=1]  Radius.
* @param {Number} [cfg.heightSegments=24] Number of latitudinal bands.
* @param  {Number} [cfg.widthSegments=18] Number of longitudinal bands.
* @returns {Object} Configuration for a {@link Geometry} subtype.
*/
function buildSphereGeometry(cfg = {}) {
	const lod = cfg.lod || 1;
	const centerX = cfg.center ? cfg.center[0] : 0;
	const centerY = cfg.center ? cfg.center[1] : 0;
	const centerZ = cfg.center ? cfg.center[2] : 0;
	let radius = cfg.radius || 1;
	if (radius < 0) {
		console.error("negative radius not allowed - will invert");
		radius *= -1;
	}
	let heightSegments = cfg.heightSegments || 18;
	if (heightSegments < 0) {
		console.error("negative heightSegments not allowed - will invert");
		heightSegments *= -1;
	}
	heightSegments = Math.floor(lod * heightSegments);
	if (heightSegments < 18) heightSegments = 18;
	let widthSegments = cfg.widthSegments || 18;
	if (widthSegments < 0) {
		console.error("negative widthSegments not allowed - will invert");
		widthSegments *= -1;
	}
	widthSegments = Math.floor(lod * widthSegments);
	if (widthSegments < 18) widthSegments = 18;
	const positions = [];
	const normals = [];
	const uvs = [];
	const indices = [];
	let i;
	let j;
	let theta;
	let sinTheta;
	let cosTheta;
	let phi;
	let sinPhi;
	let cosPhi;
	let x;
	let y;
	let z;
	let u;
	let v;
	let first;
	let second;
	for (i = 0; i <= heightSegments; i++) {
		theta = i * Math.PI / heightSegments;
		sinTheta = Math.sin(theta);
		cosTheta = Math.cos(theta);
		for (j = 0; j <= widthSegments; j++) {
			phi = j * 2 * Math.PI / widthSegments;
			sinPhi = Math.sin(phi);
			cosPhi = Math.cos(phi);
			x = cosPhi * sinTheta;
			y = cosTheta;
			z = sinPhi * sinTheta;
			u = 1 - j / widthSegments;
			v = i / heightSegments;
			normals.push(x);
			normals.push(y);
			normals.push(z);
			uvs.push(u);
			uvs.push(v);
			positions.push(centerX + radius * x);
			positions.push(centerY + radius * y);
			positions.push(centerZ + radius * z);
		}
	}
	for (i = 0; i < heightSegments; i++) for (j = 0; j < widthSegments; j++) {
		first = i * (widthSegments + 1) + j;
		second = first + widthSegments + 1;
		indices.push(first + 1);
		indices.push(second + 1);
		indices.push(second);
		indices.push(first + 1);
		indices.push(second);
		indices.push(first);
	}
	return utils.apply(cfg, {
		positions,
		normals,
		uv: uvs,
		indices
	});
}
/**
* @desc Creates a torus-shaped {@link Geometry}.
*
* ## Usage
* Creating a {@link Mesh} with a torus-shaped {@link ReadableGeometry} :
*
* [[Run this example](/examples/index.html#geometry_builders_buildTorusGeometry)]
* 
* ````javascript
* import {Viewer, Mesh, buildTorusGeometry, ReadableGeometry, PhongMaterial, Texture} from "xeokit-sdk.es.js";
*
* const viewer = new Viewer({
*      canvasId: "myCanvas"
* });
*
* viewer.camera.eye = [0, 0, 5];
* viewer.camera.look = [0, 0, 0];
* viewer.camera.up = [0, 1, 0];
*
* new Mesh(viewer.scene, {
*      geometry: new ReadableGeometry(viewer.scene, buildTorusGeometry({
*          center: [0,0,0],
*          radius: 1.0,
*          tube: 0.5,
*          radialSegments: 32,
*          tubeSegments: 24,
*          arc: Math.PI * 2.0
*      }),
*      material: new PhongMaterial(viewer.scene, {
*         diffuseMap: new Texture(viewer.scene, {
*             src: "textures/diffuse/uvGrid2.jpg"
*         })
*      })
* });
* ````
*
* @function buildTorusGeometry
* @param {*} [cfg] Configs
* @param {String} [cfg.id] Optional ID for the {@link Geometry}, unique among all components in the parent {@link Scene}, generated automatically when omitted.
* @param {Number[]} [cfg.center] 3D point indicating the center position.
* @param {Number} [cfg.radius=1] The overall radius.
* @param {Number} [cfg.tube=0.3] The tube radius.
* @param {Number} [cfg.radialSegments=32] The number of radial segments.
* @param {Number} [cfg.tubeSegments=24] The number of tubular segments.
* @param {Number} [cfg.arc=Math.PI*0.5] The length of the arc in radians, where Math.PI*2 is a closed torus.
* @returns {Object} Configuration for a {@link Geometry} subtype.
*/
function buildTorusGeometry(cfg = {}) {
	let radius = cfg.radius || 1;
	if (radius < 0) {
		console.error("negative radius not allowed - will invert");
		radius *= -1;
	}
	radius *= .5;
	let tube = cfg.tube || .3;
	if (tube < 0) {
		console.error("negative tube not allowed - will invert");
		tube *= -1;
	}
	let radialSegments = cfg.radialSegments || 32;
	if (radialSegments < 0) {
		console.error("negative radialSegments not allowed - will invert");
		radialSegments *= -1;
	}
	if (radialSegments < 4) radialSegments = 4;
	let tubeSegments = cfg.tubeSegments || 24;
	if (tubeSegments < 0) {
		console.error("negative tubeSegments not allowed - will invert");
		tubeSegments *= -1;
	}
	if (tubeSegments < 4) tubeSegments = 4;
	let arc = cfg.arc || Math.PI * 2;
	if (arc < 0) {
		console.warn("negative arc not allowed - will invert");
		arc *= -1;
	}
	if (arc > 360) arc = 360;
	const center = cfg.center;
	let centerX = center ? center[0] : 0;
	let centerY = center ? center[1] : 0;
	const centerZ = center ? center[2] : 0;
	const positions = [];
	const normals = [];
	const uvs = [];
	const indices = [];
	let u;
	let v;
	let x;
	let y;
	let z;
	let vec;
	let i;
	let j;
	for (j = 0; j <= tubeSegments; j++) for (i = 0; i <= radialSegments; i++) {
		u = i / radialSegments * arc;
		v = .785398 + j / tubeSegments * Math.PI * 2;
		centerX = radius * Math.cos(u);
		centerY = radius * Math.sin(u);
		x = (radius + tube * Math.cos(v)) * Math.cos(u);
		y = (radius + tube * Math.cos(v)) * Math.sin(u);
		z = tube * Math.sin(v);
		positions.push(x + centerX);
		positions.push(y + centerY);
		positions.push(z + centerZ);
		uvs.push(1 - i / radialSegments);
		uvs.push(j / tubeSegments);
		vec = math.normalizeVec3(math.subVec3([
			x,
			y,
			z
		], [
			centerX,
			centerY,
			centerZ
		], []), []);
		normals.push(vec[0]);
		normals.push(vec[1]);
		normals.push(vec[2]);
	}
	let a;
	let b;
	let c;
	let d;
	for (j = 1; j <= tubeSegments; j++) for (i = 1; i <= radialSegments; i++) {
		a = (radialSegments + 1) * j + i - 1;
		b = (radialSegments + 1) * (j - 1) + i - 1;
		c = (radialSegments + 1) * (j - 1) + i;
		d = (radialSegments + 1) * j + i;
		indices.push(a);
		indices.push(b);
		indices.push(c);
		indices.push(c);
		indices.push(d);
		indices.push(a);
	}
	return utils.apply(cfg, {
		positions,
		normals,
		uv: uvs,
		indices
	});
}
